	[Fact]
	public async Task FirstOccurrence_IsWrittenAsIs() =>
		await RunCase(
			0.30, 0.10,
			[ "A", 200 ],					// single log, allow writer to flush
			[
				new PlainExp("A", 1),		// first occurrence is written normally
				new DupExp("A", 0),			// no duplicate annotation
				new SummaryExp("A", 0)		// no pause summary
			]
		);

	[Fact]
	public async Task DuplicateWithinWindow_ForcedSummary_CountsSuppressed() =>
		await RunCase(
			0.40, 0.10,
			[
				"X",
				50,
				"X",						// first duplicate → pause starts
				(2, "X"),					// suppressed duplicates during pause
				1500						// allow monitor to force summary
			],
			[
				new PlainExp("X", 1),				// first occurrence
				new DupExp("X", 1),					// one duplicate annotation
				new SummaryExp("X", 1, Repeated:2),	// forced summary with 2 suppressed
				new SummaryPlusExp("X", false)		// critical: forced path has no +1
			]
		);

	[Fact]
	public async Task NaturalSummary_WhenMessageArrivesAfterPause() =>
		await RunCase(
			0.25, 5.0,						// large force window to avoid monitor forcing
			[
				"N",
