				"N",						// duplicate → pause starts
				350,						// wait past pause end
				"N",						// natural summary triggered by next log
				200
			],
			[
				new PlainExp("N", 1),				// first occurrence
				new DupExp("N", 1),					// duplicate annotation
				new SummaryExp("N", 1, Repeated:1),	// natural summary = 0 suppressed + 1
				new SummaryPlusExp("N", true)		// proves natural path (+1)
			]
		);

